```python
def is_prime(num):
    if num <= 1:
        return False
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            return False
    return True

def fibonacci():
    a, b = 0, 1
    while True:
        yield b
        a, b = b, a + b

def prime_fib(n: int):
    primes = []
    for fib in fibonacci():
        if is_prime(fib):
            primes.append(fib)
        if len(primes) == n:
            return primes[-1]
```

